"""
tests/contract/test_vcf_schema.py

Contract test for VCF schema validation.
Ensures that the synthetic VCF generated by T009 adheres to the expected schema.
"""

import pytest
import json
from pathlib import Path
from code.utils.validators.snp_schema import SnpSchema, validate_snp_data

# Path to the synthetic VCF generated by T009
SYNTHETIC_VCF_PATH = Path("data/interim/synthetic.vcf")

def parse_vcf_header(vcf_path: Path):
    """Parses VCF header to extract metadata."""
    meta = {}
    with open(vcf_path, "r") as f:
        for line in f:
            if line.startswith("##"):
                key, value = line[2:].split("=", 1)
                meta[key] = value.strip('"')
            elif line.startswith("#CHROM"):
                # Parse column names
                cols = line.strip().split("\t")
                return meta, cols
    return meta, []

def test_vcf_schema_conformance():
    """
    Validates that the synthetic VCF file conforms to the expected schema.
    """
    if not SYNTHETIC_VCF_PATH.exists():
        pytest.skip(f"Synthetic VCF not found at {SYNTHETIC_VCF_PATH}. Run T009 first.")

    try:
        meta, columns = parse_vcf_header(SYNTHETIC_VCF_PATH)
        
        # Contract 1: Required meta headers
        assert "fileformat" in meta, "Missing fileformat meta header"
        assert meta["fileformat"] == "VCFv4.2", f"Expected VCFv4.2, got {meta['fileformat']}"
        
        # Contract 2: Required columns
        required_cols = ["#CHROM", "POS", "ID", "REF", "ALT", "QUAL", "FILTER", "INFO"]
        for col in required_cols:
            assert col in columns, f"Missing required column: {col}"
        
        # Contract 3: Validate data rows against schema
        # Read the rest of the file as data
        with open(SYNTHETIC_VCF_PATH, "r") as f:
            lines = f.readlines()
        
        data_lines = [l for l in lines if not l.startswith("##") and not l.startswith("#CHROM")]
        
        if len(data_lines) > 0:
            # Parse first data line to check structure
            first_row = data_lines[0].strip().split("\t")
            assert len(first_row) == len(columns), "Column count mismatch in data row"
            
            # Validate types using schema
            # Note: SnpSchema expects a dict structure, so we convert
            row_dict = dict(zip(columns, first_row))
            
            # Basic validation using the schema defined in utils
            # This assumes the schema validates types and required fields
            is_valid, errors = validate_snp_data(row_dict)
            assert is_valid, f"Data row failed schema validation: {errors}"

    except Exception as e:
        pytest.fail(f"VCF Schema validation failed: {e}")

def test_vcf_content_validity():
    """
    Checks for basic content validity (e.g., no empty fields, valid chromosomes).
    """
    if not SYNTHETIC_VCF_PATH.exists():
        pytest.skip(f"Synthetic VCF not found at {SYNTHETIC_VCF_PATH}.")

    with open(SYNTHETIC_VCF_PATH, "r") as f:
        lines = f.readlines()

    data_lines = [l for l in lines if not l.startswith("##") and not l.startswith("#CHROM")]
    
    for i, line in enumerate(data_lines):
        parts = line.strip().split("\t")
        if len(parts) < 8:
            pytest.fail(f"Line {i+1} has insufficient columns: {line}")
        
        # Check REF and ALT are not empty
        if parts[3] == "" or parts[4] == "":
            pytest.fail(f"Line {i+1} has empty REF or ALT")
        
        # Check POS is integer
        try:
            int(parts[1])
        except ValueError:
            pytest.fail(f"Line {i+1} has non-integer POS")
